<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Falling Sand Sandbox</title>
    <style>
        :root {
            --bg-color: #1a1a1a;
            --panel-bg: #252525;
            --text-color: #e0e0e0;
            --accent-color: #4CAF50;
            --border-color: #333;
        }

        body {
            margin: 0;
            padding: 0;
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            justify-content: center;
            align-items: center;
            height: 100vh;
            overflow: hidden;
        }

        #app-container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 20px;
            padding: 20px;
            background-color: var(--panel-bg);
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
        }

        canvas {
            background-color: #000;
            border: 2px solid var(--border-color);
            cursor: crosshair;
            image-rendering: pixelated; /* Keep pixels sharp */
            box-shadow: inset 0 0 20px rgba(0,0,0,0.8);
        }

        #controls {
            display: flex;
            gap: 10px;
            flex-wrap: wrap;
            justify-content: center;
            width: 100%;
            max-width: 640px;
        }

        button {
            padding: 8px 16px;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            font-weight: bold;
            font-size: 14px;
            transition: transform 0.1s, opacity 0.2s;
            text-transform: uppercase;
            letter-spacing: 0.5px;
        }

        button:hover {
            transform: translateY(-1px);
            filter: brightness(1.1);
        }

        button:active {
            transform: translateY(1px);
        }

        .btn-sand { background-color: #fbc02d; color: #3e270f; border: 1px solid #f57f17; }
        .btn-water { background-color: #4fc3f7; color: #01579b; border: 1px solid #0288d1; }
        .btn-wall { background-color: #757575; color: #263238; border: 1px solid #424242; }
        .btn-acid { background-color: #b2dfdb; color: #004d40; border: 1px solid #00695c; }
        .btn-empty { background-color: #37474f; color: #eceff1; border: 1px solid #546e7a; }

        .btn-clear { 
            background-color: #d32f2f; 
            color: white; 
            border: 1px solid #b71c1c; 
            margin-top: 10px;
        }

        /* Active state for selection */
        button.selected {
            box-shadow: 0 0 0 2px rgba(255,255,255,0.3);
            transform: scale(1.05);
